def main():
    df = pd.DataFrame(data)
    out_path = Path("data/scheduler_ko.parquet")
    out_path.parent.mkdir(parents=True, exist_ok=True)
    df.to_parquet(out_path, index=False)
    
    # 기존 체크포인트가 있으면 삭제하여 꼬임 방지
    ckpt_path = out_path.with_suffix(".ckpt.jsonl")
    if ckpt_path.exists():
        ckpt_path.unlink()
        print("[체크포인트] 기존 scheduler_ko.ckpt.jsonl 삭제 완료")
        
    print(f"[완료] 직접 가공한 20개 고품질 데이터셋 저장 성공 -> {out_path}")

if __name__ == "__main__":
    main()
